 28→export const listConfiguredModels = orgAction(
 29→  z.object({
 30→    sandboxId: z.string().min(1),
 31→  }),
 32→  async ({ organizationId }, input) => {
 33→    const runtime = await getSandboxRuntime(input.sandboxId, organizationId);
 34→    const cmd = `openclaw models list --json`;
 35→    const result = await runOrThrow(runtime, cmd, "listConfiguredModels");
 36→
 37→    try {
 38→      const parsed = JSON.parse(result.stdout.trim() || "{}") as unknown;
 39→
 40→      if (
 41→        parsed &&
 42→        typeof parsed === "object" &&
 43→        Array.isArray((parsed as { models?: unknown[] }).models)
 44→      ) {
 45→        const models = (
 46→          parsed as {
 47→            models: {
 48→              key?: string;
 49→              name?: string;
 50→              tags?: string[];
 51→            }[];
 52→          }
 53→        ).models;
 54→
 55→        return models
 56→          .filter(
 57→            (m) =>
 58→              typeof m.key === "string" &&
 59→              Array.isArray(m.tags) &&
 60→              m.tags.includes("configured"),
 61→          )
 62→          .map((m) => {
 63→            const key = m.key as string;
 64→            const tags = m.tags ?? [];
 65→            const lower = key.toLowerCase();
 66→
 67→            let provider: "openai" | "anthropic" | "openrouter" | "other" =
 68→              "other";
 69→            if (lower.includes("openai")) provider = "openai";
 70→            else if (lower.includes("anthropic")) provider = "anthropic";
 71→            else if (lower.includes("openrouter")) provider = "openrouter";
 72→
 73→            return {
 74→              key,
 75→              name: m.name ?? key,
 76→              isDefault: tags.includes("default"),
 77→              provider,
 78→            };
 79→          });
 80→      }
 81→
 82→      return [] as {
 83→        key: string;
 84→        name: string;
 85→        isDefault: boolean;
 86→        provider: string;
 87→      }[];
 88→    } catch {
 89→      return [] as {
 90→        key: string;
 91→        name: string;
 92→        isDefault: boolean;
 93→        provider: string;
 94→      }[];
 95→    }
 96→  },
 97→);
