 99→export const listProviderModels = orgAction(
100→  z.object({
101→    sandboxId: z.string().min(1),
102→    provider: z.enum(["openai", "anthropic", "openrouter"]),
103→  }),
104→  async ({ organizationId }, input) => {
105→    const runtime = await getSandboxRuntime(input.sandboxId, organizationId);
106→    const cmd = `openclaw models list --provider ${input.provider} --all --json`;
107→    const result = await runOrThrow(runtime, cmd, "listProviderModels");
108→    const parsed = JSON.parse(result.stdout.trim() || "[]") as unknown;
109→
110→    let models: { id: string; name?: string }[] = [];
111→
112→    // Newer OpenClaw returns: { count, models: [{ key, name, ... }] }
113→    if (
114→      parsed &&
115→      typeof parsed === "object" &&
116→      Array.isArray((parsed as { models?: unknown }).models)
117→    ) {
118→      models = (parsed as { models: unknown[] }).models
119→        .map((m) => m as { key?: string; name?: string })
120→        .filter((m) => typeof m.key === "string")
121→        .map((m) => ({
122→          id: m.key as string,
123→          name: m.name,
124→        }));
125→    } else if (Array.isArray(parsed)) {
126→      // Fallback: plain array of models (legacy shape)
127→      models = parsed
128→        .map((m) => m as { id?: string; key?: string; name?: string })
129→        .filter((m) => typeof (m.id ?? m.key) === "string")
130→        .map((m) => ({
131→          id: (m.id ?? m.key) as string,
132→          name: m.name,
133→        }));
134→    }
135→
136→    // Reverse (newest first), take latest 5
137→    return models.reverse().slice(0, 5);
138→  },
139→);
