 3→export function buildOnboardCmd(provider: string, apiKey: string): string {
 4→  const base = `openclaw onboard --non-interactive --accept-risk`;
 5→  switch (provider) {
 6→    case "openai":
 7→      return `${base} --auth-choice openai-api-key --openai-api-key ${esc(apiKey)}`;
 8→    case "anthropic":
 9→      return `${base} --anthropic-api-key ${esc(apiKey)}`;
10→    case "openrouter":
11→      return `${base} --auth-choice openrouter-api-key --openrouter-api-key ${esc(apiKey)}`;
12→    default:
13→      throw new Error(`Unknown provider: ${provider}`);
14→  }
15→}
