 1→import { defaultBuildLogger, Template } from "e2b";
 2→
 3→const TEMPLATE_NAME = "runagents-dev-20260227";
 4→const CPU_COUNT = 2;
 5→const MEMORY_MB = 1024 * 4;
 6→
 7→const OPENROUTER_API_KEY =
 8→  process.env.OPENROUTER_API_KEY || "sk-or-v1-dummy-key";
 9→// Onboarding is baked into the image to avoid repeating the slowest step at creation time.
10→// Model + credential + channel config is applied per-sandbox by the create action.
11→const template = Template()
12→  .fromNodeImage("22")
13→  .aptInstall(["curl", "git", "wget", "jq", "dbus", "dbus-user-session"])
14→  // Enable linger for the default sandbox user so user@UID.service starts on boot.
15→  // The profile.d script sets XDG_RUNTIME_DIR dynamically for any shell session.
16→  .runCmd(
17→    "sudo mkdir -p /var/lib/systemd/linger && sudo touch /var/lib/systemd/linger/user",
18→  )
19→  .runCmd(
20→    "printf 'export XDG_RUNTIME_DIR=/run/user/$(id -u)\\nexport DBUS_SESSION_BUS_ADDRESS=unix:path=/run/user/$(id -u)/bus\\nexport PATH=$HOME/.npm-global/bin:$PATH\\n' | sudo tee /etc/profile.d/user-session.sh > /dev/null && sudo chmod +x /etc/profile.d/user-session.sh",
21→  )
22→  .runCmd(
23→    "curl -fsSL https://openclaw.ai/install.sh | bash -s -- --no-prompt --no-onboard",
24→  )
25→  .runCmd(
26→    `openclaw onboard \
27→--non-interactive --accept-risk \
28→--flow quickstart \
29→--gateway-bind loopback --gateway-auth token \
30→--skip-health \
31→--install-daemon \
32→--auth-choice openrouter-api-key \
33→--openrouter-api-key "${OPENROUTER_API_KEY}"`,
34→  );
35→
36→async function main() {
37→  console.log(`Building E2B template "${TEMPLATE_NAME}"...\n`);
38→
39→  const buildInfo = await Template.build(template, TEMPLATE_NAME, {
40→    cpuCount: CPU_COUNT,
41→    memoryMB: MEMORY_MB,
42→    onBuildLogs: defaultBuildLogger(),
43→  });
44→
45→  console.log("Template built successfully.");
46→  console.log(`  Name:        ${buildInfo.name}`);
47→  console.log(`  Template ID: ${buildInfo.templateId}`);
48→  console.log(`  Build ID:    ${buildInfo.buildId}`);
49→}
50→
51→main().catch((err) => {
52→  console.error("Build failed:", err);
53→  process.exit(1);
54→});
